import axios from "axios";

const api = axios.create({
    baseURL: process.env.REACT_APP_API_BASE || "http://localhost:8080",
});

function getToken() {
    // ưu tiên session trước (không ghi nhớ), sau đó tới local
    return sessionStorage.getItem("access_token") || localStorage.getItem("access_token");
}

api.interceptors.request.use((config) => {
    const t = getToken();
    if (t) config.headers.Authorization = `Bearer ${t}`;
    return config;
});

api.interceptors.response.use(
    (res) => res,
    (err) => {
        if (err?.response?.status === 401) {
            // Hết hạn hoặc token invalid -> dọn token ở cả 2
            sessionStorage.removeItem("access_token");
            localStorage.removeItem("access_token");
            // tuỳ chọn: window.location.assign('/login');
        }
        return Promise.reject(err);
    }
);

/** ========= Nhóm API tiện dụng ========= **/
export const users = {
    list: (params = {}) => api.get("/users", { params }).then(r => r.data),
    get: (id) => api.get(`/users/${id}`).then(r => r.data),
    create: (payload) => api.post("/users", payload).then(r => r.data),
    update: (id, payload) => api.put(`/users/${id}`, payload).then(r => r.data),
    remove: (id) => api.delete(`/users/${id}`).then(r => r.data),
};

export const roles = {
    list: () => api.get("/roles").then(r => r.data), // [{id,name,systemRole,description,count}]
    create: (name, description="") => api.post("/roles", { name, description }).then(r => r.data),
    remove: (id) => api.delete(`/roles/${id}`).then(r => r.data),
};

export default api;
